import React, { useMemo, useState } from 'react';
import {
  dispatchAppToast,
  erpReportTableConfigFromDisplay,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinPageLayout,
  LinReportPrintScopeModal,
  LinReportTableConfigModal,
  loadErpReportDisplayConfig,
  saveErpReportDisplayConfig,
  useCatalogTableBusy,
  type ErpReportDisplayConfig,
  type ReportPrintScope,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import erp from '../../styles/erpPage.module.css';
import reportStyles from '../../styles/erpReportPage.module.css';
import type { ReportChartOption } from '../../services/analytics/models';
import { mapReportChartCatalog } from '../../utils/buildReportChartQueryParams';

export type AnalyticsReportShellProps = {
  testId: string;
  pageId: string;
  title: string;
  titleIconClass?: string;
  listTitle?: string;
  loading: boolean;
  hasData: boolean;
  /** LinErpListFilterBar node — omit for dashboard / no filter */
  filters?: React.ReactNode;
  onLoad: () => void;
  tabBar?: React.ReactNode;
  emptyMessage?: string;
  children: React.ReactNode;
  /** When present, toolbar shows chart button and report chart config section is shown. */
  chartCatalog?: ReportChartOption[];
  /** BE chart data for chart modal rendering. */
  chartData?: unknown;
  /** Footer pagination (VoucherListPagination). */
  footer?: React.ReactNode;
  /** Props passed through to LinReportTableConfigModal (VN labels). */
  configLabels?: {
    title?: string;
    sectionGrid?: string;
    sectionFooter?: string;
    sectionPrint?: string;
    printBatchSizeLabel?: string;
    printBatchSizeHint?: string;
    sectionChart?: string;
    chartEmptyHint?: string;
  };
  /** Print scope modal labels. */
  printLabels?: {
    title?: string;
    scopeLabel?: string;
    currentPageOption?: string;
    allPagesOption?: string;
    cancel?: string;
    confirm?: string;
    fetchHint?: string;
  };
  /** When true, handlePrint is called for toolbar print. Default: shows LinReportPrintScopeModal. */
  onPrint?: () => void;
  /** When true, handleChart is called for toolbar chart. Default: shows info toast. */
  onChart?: () => void;
  /** Show/hide print button. */
  canPrint?: boolean;
  /** Show/hide chart button. */
  canChart?: boolean;
  /** Legacy export props — keep for backward compatibility. */
  exportPath?: string;
  exportParams?: Record<string, string | number | boolean | undefined>;
  exportFilename?: string;
  /** Dashboard / import tracker — always render body */
  suppressEmptyGate?: boolean;
};

const DEFAULT_EMPTY = 'Chọn bộ lọc và bấm Xem';

export const AnalyticsReportShell: React.FC<AnalyticsReportShellProps> = ({
  testId,
  pageId,
  title,
  titleIconClass = 'fas fa-file-alt',
  listTitle,
  loading,
  hasData,
  filters,
  onLoad,
  tabBar,
  emptyMessage = DEFAULT_EMPTY,
  children,
  chartCatalog,
  chartData,
  footer,
  configLabels,
  printLabels: printLabelsProp,
  onPrint,
  onChart,
  canPrint,
  canChart,
  suppressEmptyGate,
}) => {
  const dispatch = useAppDispatch();
  const [configOpen, setConfigOpen] = useState(false);
  const [printModalOpen, setPrintModalOpen] = useState(false);
  const [displayConfig, setDisplayConfig] = useState<ErpReportDisplayConfig>(() =>
    loadErpReportDisplayConfig(testId),
  );
  const { showTableLoading } = useCatalogTableBusy(loading);

  const tableConfig = useMemo(
    () => erpReportTableConfigFromDisplay(displayConfig),
    [displayConfig],
  );

  const handleSaveDisplayConfig = (next: ErpReportDisplayConfig) => {
    setDisplayConfig(next);
    saveErpReportDisplayConfig(testId, next);
  };

  const handlePrint = () => {
    if (onPrint) {
      onPrint();
      return;
    }
    if (hasData) setPrintModalOpen(true);
    else {
      dispatchAppToast(dispatch, { message: 'Không có dữ liệu để in', type: 'info' });
    }
  };

  const handleChart = () => {
    if (onChart) {
      onChart();
      return;
    }
    if (chartData && hasData) {
      dispatchAppToast(dispatch, { message: 'Biểu đồ — đang phát triển', type: 'info' });
    }
  };

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: testId,
      onRefresh: onLoad,
      canChart: canChart ?? (hasData && !!chartCatalog && chartCatalog.length > 0 && !!chartData),
      onChart: handleChart,
      canPrint: canPrint ?? hasData,
      onPrint: handlePrint,
      onEditConfig: () => setConfigOpen(true),
    }),
    [testId, onLoad, canChart, handleChart, canPrint, handlePrint, hasData, chartCatalog, chartData],
  );

  const listBody = (
    <>
      {tabBar}
      {!showTableLoading && !hasData && !suppressEmptyGate ? (
        <div
          className={`${erp.empty} ${reportStyles.emptyFill}`}
          data-testid={`${testId}-empty`}
        >
          {emptyMessage}
        </div>
      ) : !showTableLoading ? (
        children
      ) : null}
    </>
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${testId}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={testId}
        pageId={pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title,
          titleIconClass,
          pageId,
        }}
        reportToolbar={reportToolbar}
        listTitle={listTitle ?? title}
        filters={filters}
        listLayoutVariant={filters ? 'erp-filter-bar' : undefined}
        listHeaderClassName={filters ? LIN_ERP_LIST_FILTER_LAYOUT.header : undefined}
        listFiltersClassName={filters ? LIN_ERP_LIST_FILTER_LAYOUT.filtersHost : undefined}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={footer}
        modals={(
          <>
            <LinReportTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={testId}
              config={displayConfig}
              chartCatalog={mapReportChartCatalog(chartCatalog)}
              onSave={handleSaveDisplayConfig}
              title={configLabels?.title}
              sectionGridLabel={configLabels?.sectionGrid}
              sectionFooterLabel={configLabels?.sectionFooter}
              sectionPrintLabel={configLabels?.sectionPrint}
              printBatchSizeLabel={configLabels?.printBatchSizeLabel}
              printBatchSizeHint={configLabels?.printBatchSizeHint}
              sectionChartLabel={configLabels?.sectionChart}
              chartEmptyHint={configLabels?.chartEmptyHint}
            />
            <LinReportPrintScopeModal
              isOpen={printModalOpen}
              onClose={() => setPrintModalOpen(false)}
              onConfirm={async (scope: ReportPrintScope) => {
                setPrintModalOpen(false);
                if (onPrint) onPrint();
              }}
              printing={false}
              testIdPrefix={testId}
              currentPage={1}
              currentPageRowCount={0}
              totalCount={0}
              showAllPagesOption={false}
              labels={printLabelsProp}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

/** Tab switcher — use inside AnalyticsReportShell tabBar */
export const ReportTabBar: React.FC<{
  testId: string;
  tabs: { id: string; label: string }[];
  activeId: string;
  onChange: (id: string) => void;
}> = ({ testId, tabs, activeId, onChange }) => (
  <div className={reportStyles.tabs} data-testid={`${testId}-tabs`}>
    {tabs.map(t => (
      <button
        key={t.id}
        type="button"
        className={activeId === t.id ? reportStyles.tabActive : reportStyles.tab}
        onClick={() => onChange(t.id)}
      >
        {t.label}
      </button>
    ))}
  </div>
);

export const ReportTableWrap: React.FC<{ children: React.ReactNode; testId?: string }> = ({
  children,
  testId,
}) => (
  <div className={reportStyles.tableWrapper}>
    <table className={reportStyles.table} data-testid={testId}>
      {children}
    </table>
  </div>
);
